const e=JSON.parse(`[{"id":1,"section":"A","theme":"Daily activities","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une personne court dans le parc","image_prompt":"A person running in a green park, sunny day"},{"id":"B","text":"Une personne fait du vélo","image_prompt":"A person riding a bicycle on a city path"},{"id":"C","text":"Une personne nage","image_prompt":"A person swimming in a blue pool"},{"id":"D","text":"Une personne marche avec un chien","image_prompt":"A person walking a golden retriever in a park"}],"correct":0,"transcript_fr":"J'adore commencer ma journée par un petit footing au parc quand il fait beau.","transcript_en":"I love starting my day with a quick jog in the park when the weather is nice.","points":[{"point":1,"male_lines":["J'adore commencer ma journée par un petit footing au parc quand il fait beau."],"female_lines":[]}]},{"id":2,"section":"A","theme":"Transportation","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un autobus scolaire","image_prompt":"A yellow school bus on a street"},{"id":"B","text":"Un métro souterrain","image_prompt":"A subway train arriving at an underground station"},{"id":"C","text":"Un taxi jaune","image_prompt":"A yellow taxi cab on a city street"},{"id":"D","text":"Un train de banlieue","image_prompt":"A commuter train at a platform"}],"correct":1,"transcript_fr":"Je prends toujours le métro pour aller travailler, c'est plus rapide que l'autobus.","transcript_en":"I always take the subway to go to work, it's faster than the bus.","points":[{"point":1,"male_lines":["Je prends toujours le métro pour aller travailler, c'est plus rapide que l'autobus."],"female_lines":[]}]},{"id":3,"section":"A","theme":"Food and drink","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une tasse de café","image_prompt":"A steaming cup of coffee on a table"},{"id":"B","text":"Un verre de jus d'orange","image_prompt":"A glass of orange juice with fresh oranges"},{"id":"C","text":"Une bouteille d'eau","image_prompt":"A bottle of water on a white background"},{"id":"D","text":"Un bol de soupe","image_prompt":"A bowl of hot soup with vegetables"}],"correct":0,"transcript_fr":"Rien ne vaut un bon café chaud le matin pour bien commencer la journée.","transcript_en":"Nothing beats a good hot coffee in the morning to start the day right.","points":[{"point":1,"male_lines":["Rien ne vaut un bon café chaud le matin pour bien commencer la journée."],"female_lines":[]}]},{"id":4,"section":"A","theme":"Weather","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un ciel ensoleillé","image_prompt":"A bright sunny sky with few clouds"},{"id":"B","text":"De la neige qui tombe","image_prompt":"Snow falling on a winter landscape"},{"id":"C","text":"Un orage avec éclairs","image_prompt":"A thunderstorm with lightning in dark clouds"},{"id":"D","text":"De la pluie fine","image_prompt":"Light rain falling on a window"}],"correct":3,"transcript_fr":"N'oublie pas ton parapluie, il pleut des cordes dehors!","transcript_en":"Don't forget your umbrella, it's pouring rain outside!","points":[{"point":1,"male_lines":["N'oublie pas ton parapluie, il pleut des cordes dehors!"],"female_lines":[]}]},{"id":5,"section":"A","theme":"Shopping","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un panier d'épicerie plein","image_prompt":"A full grocery basket with vegetables and fruits"},{"id":"B","text":"Un caddie de supermarché","image_prompt":"A shopping cart in a supermarket aisle"},{"id":"C","text":"Un sac de magasinage réutilisable","image_prompt":"A reusable shopping bag with items inside"},{"id":"D","text":"Une liste de courses","image_prompt":"A handwritten grocery list on paper"}],"correct":2,"transcript_fr":"J'ai apporté mes propres sacs pour faire mes courses, c'est plus écologique.","transcript_en":"I brought my own bags for shopping, it's more ecological.","points":[{"point":1,"male_lines":["J'ai apporté mes propres sacs pour faire mes courses, c'est plus écologique."],"female_lines":[]}]},{"id":6,"section":"A","theme":"Work","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un bureau avec ordinateur","image_prompt":"A desk with a computer and office supplies"},{"id":"B","text":"Une réunion en salle de conférence","image_prompt":"A business meeting in a conference room"},{"id":"C","text":"Une personne travaillant à domicile","image_prompt":"A person working on a laptop at home"},{"id":"D","text":"Un employé au téléphone","image_prompt":"An employee talking on the phone at a desk"}],"correct":2,"transcript_fr":"Depuis la pandémie, je travaille de la maison trois jours par semaine.","transcript_en":"Since the pandemic, I work from home three days a week.","points":[{"point":1,"male_lines":["Depuis la pandémie, je travaille de la maison trois jours par semaine."],"female_lines":[]}]},{"id":7,"section":"B","theme":"Everyday conversation - Restaurant","question":"Que va faire l'homme ?","options":[{"id":"A","text":"Il va payer l'addition","image_prompt":""},{"id":"B","text":"Il va commander le dessert","image_prompt":""},{"id":"C","text":"Il va appeler le serveur","image_prompt":""},{"id":"D","text":"Il va quitter le restaurant","image_prompt":""}],"correct":1,"transcript_fr":"Homme: Excusez-moi, est-ce que vous avez encore de la tarte aux pommes? Femme: Oui monsieur, nous en avons. Homme: Parfait, je vais en prendre une part s'il vous plaît. Femme: Tout de suite, monsieur.","transcript_en":"Man: Excuse me, do you still have apple pie? Woman: Yes sir, we do. Man: Perfect, I'll have a slice please. Woman: Right away, sir.","points":[{"point":1,"male_lines":["Excusez-moi, est-ce que vous avez encore de la tarte aux pommes?","Parfait, je vais en prendre une part s'il vous plaît."],"female_lines":["Oui monsieur, nous en avons.","Tout de suite, monsieur."]},{"point":2,"male_lines":["J'ai vraiment envie de quelque chose de sucré pour finir."],"female_lines":["Je vous recommande notre tarte, elle est excellente aujourd'hui."]},{"point":3,"male_lines":["D'accord, je vais suivre votre conseil alors."],"female_lines":["Je vous apporte ça avec un peu de crème glacée?"]},{"point":4,"male_lines":["Oui, excellente idée, merci beaucoup."],"female_lines":["Je reviens dans deux minutes avec votre dessert."]}]},{"id":8,"section":"B","theme":"Everyday conversation - Directions","question":"Où se trouve la bibliothèque ?","options":[{"id":"A","text":"À côté de la banque","image_prompt":""},{"id":"B","text":"En face du parc","image_prompt":""},{"id":"C","text":"Derrière la mairie","image_prompt":""},{"id":"D","text":"Au coin de la rue","image_prompt":""}],"correct":0,"transcript_fr":"Femme: Pardon monsieur, je cherche la bibliothèque municipale. Homme: C'est juste à côté de la banque, madame. Femme: Ah oui? Je ne l'avais pas vue. Homme: Oui, c'est le grand bâtiment gris avec les fenêtres bleues.","transcript_en":"Woman: Excuse me sir, I'm looking for the municipal library. Man: It's right next to the bank, ma'am. Woman: Oh really? I hadn't seen it. Man: Yes, it's the big gray building with blue windows.","points":[{"point":1,"male_lines":["C'est juste à côté de la banque, madame.","Oui, c'est le grand bâtiment gris avec les fenêtres bleues."],"female_lines":["Pardon monsieur, je cherche la bibliothèque municipale.","Ah oui? Je ne l'avais pas vue."]},{"point":2,"male_lines":["Vous ne pouvez pas la manquer, elle est vraiment imposante."],"female_lines":["Je suis nouvelle dans le quartier, je m'oriente encore mal."]},{"point":3,"male_lines":["Ce n'est pas grave, c'est normal quand on arrive quelque part."],"female_lines":["Est-ce que je peux y aller à pied d'ici?"]},{"point":4,"male_lines":["Oui, c'est à cinq minutes à pied tout droit."],"female_lines":["Merci beaucoup pour votre aide, monsieur."]}]},{"id":9,"section":"B","theme":"Everyday conversation - Appointment","question":"Quand est rendez-vous ?","options":[{"id":"A","text":"Demain matin","image_prompt":""},{"id":"B","text":"Aujourd'hui après-midi","image_prompt":""},{"id":"C","text":"La semaine prochaine","image_prompt":""},{"id":"D","text":"Dans deux jours","image_prompt":""}],"correct":1,"transcript_fr":"Homme: Bonjour, j'ai rendez-vous avec le docteur Tremblay. Femme: Oui monsieur, vous êtes bien enregistré pour cet après-midi à 14h. Homme: Parfait, je suis un peu en avance. Femme: Ce n'est pas grave, asseyez-vous dans la salle d'attente.","transcript_en":"Man: Hello, I have an appointment with Dr. Tremblay. Woman: Yes sir, you are indeed registered for this afternoon at 2 PM. Man: Perfect, I'm a bit early. Woman: That's fine, please have a seat in the waiting room.","points":[{"point":1,"male_lines":["Bonjour, j'ai rendez-vous avec le docteur Tremblay.","Parfait, je suis un peu en avance."],"female_lines":["Oui monsieur, vous êtes bien enregistré pour cet après-midi à 14h.","Ce n'est pas grave, asseyez-vous dans la salle d'attente."]},{"point":2,"male_lines":["Le docteur sera-t-il long à me recevoir?"],"female_lines":["Non, il en a pour quelques minutes seulement."]},{"point":3,"male_lines":["D'accord, je vais patienter tranquillement alors."],"female_lines":["Voulez-vous un verre d'eau en attendant?"]},{"point":4,"male_lines":["Non merci, je suis très bien comme ça."],"female_lines":["Très bien, je viens vous chercher quand c'est votre tour."]}]},{"id":10,"section":"B","theme":"Everyday conversation - Shopping","question":"Quelle taille cherche la femme ?","options":[{"id":"A","text":"La taille petite","image_prompt":""},{"id":"B","text":"La taille moyenne","image_prompt":""},{"id":"C","text":"La taille grande","image_prompt":""},{"id":"D","text":"La taille extra-large","image_prompt":""}],"correct":2,"transcript_fr":"Femme: Bonjour, est-ce que vous avez ce manteau en taille grande? Homme: Oui madame, je vais voir en arrière. Femme: Merci, la taille moyenne est trop serrée pour moi. Homme: Voilà, essayez celle-ci, la coupe est très belle.","transcript_en":"Woman: Hello, do you have this coat in large size? Man: Yes ma'am, I'll check in the back. Woman: Thank you, the medium size is too tight for me. Man: Here, try this one, the cut is very nice.","points":[{"point":1,"male_lines":["Oui madame, je vais voir en arrière.","Voilà, essayez celle-ci, la coupe est très belle."],"female_lines":["Bonjour, est-ce que vous avez ce manteau en taille grande?","Merci, la taille moyenne est trop serrée pour moi."]},{"point":2,"male_lines":["Je pense que celle-ci vous ira parfaitement."],"female_lines":["J'espère, j'ai besoin d'un manteau chaud pour l'hiver."]},{"point":3,"male_lines":["Celui-ci est doublé en laine, il tient très chaud."],"female_lines":["C'est exactement ce qu'il me faut alors."]},{"point":4,"male_lines":["Les cabines d'essayage sont par là si vous voulez essayer."],"female_lines":["Merci, je vais l'essayer tout de suite."]}]},{"id":11,"section":"C","theme":"Public announcement - Train station","question":"Qu'est-ce que les voyageurs doivent faire ?","options":[{"id":"A","text":"Changer de quai","image_prompt":""},{"id":"B","text":"Attendre une annonce","image_prompt":""},{"id":"C","text":"Monter immédiatement dans le train","image_prompt":""},{"id":"D","text":"Se rendre au bureau d'information","image_prompt":""}],"correct":0,"transcript_fr":"Mesdames et messieurs, nous vous informons que le train 45 à destination de Québec partira désormais du quai numéro 5 au lieu du quai numéro 3. Nous vous prions de bien vouloir vous diriger vers le nouveau quai. Le départ est maintenu à 14h30. Nous vous remercions de votre compréhension.","transcript_en":"Ladies and gentlemen, we inform you that train 45 to Quebec will now depart from platform number 5 instead of platform number 3. Please proceed to the new platform. Departure is maintained at 2:30 PM. Thank you for your understanding.","points":[{"point":1,"male_lines":["Mesdames et messieurs, nous vous informons que le train 45 à destination de Québec partira désormais du quai numéro 5 au lieu du quai numéro 3."],"female_lines":[]},{"point":2,"male_lines":["Nous vous prions de bien vouloir vous diriger vers le nouveau quai."],"female_lines":[]},{"point":3,"male_lines":["Le départ est maintenu à 14h30."],"female_lines":[]},{"point":4,"male_lines":["Nous vous remercions de votre compréhension."],"female_lines":[]}]},{"id":12,"section":"C","theme":"Public announcement - Supermarket","question":"Quelle promotion est annoncée ?","options":[{"id":"A","text":"50% sur les fruits","image_prompt":""},{"id":"B","text":"2 pour 1 sur le pain","image_prompt":""},{"id":"C","text":"30% sur les produits laitiers","image_prompt":""},{"id":"D","text":"Offre spéciale sur le fromage","image_prompt":""}],"correct":3,"transcript_fr":"Chers clients, profitez de notre offre exceptionnelle du jour sur tous les fromages fins. Jusqu'à 18h ce soir, bénéficiez d'une réduction de 40% sur l'ensemble de notre sélection de fromages québécois et importés. Cette offre est valable uniquement aujourd'hui. Rendez-vous au rayon fromagerie.","transcript_en":"Dear customers, take advantage of our exceptional offer of the day on all fine cheeses. Until 6 PM tonight, benefit from a 40% reduction on our entire selection of Quebec and imported cheeses. This offer is valid only today. Go to the cheese section.","points":[{"point":1,"male_lines":["Chers clients, profitez de notre offre exceptionnelle du jour sur tous les fromages fins."],"female_lines":[]},{"point":2,"male_lines":["Jusqu'à 18h ce soir, bénéficiez d'une réduction de 40% sur l'ensemble de notre sélection de fromages québécois et importés."],"female_lines":[]},{"point":3,"male_lines":["Cette offre est valable uniquement aujourd'hui."],"female_lines":[]},{"point":4,"male_lines":["Rendez-vous au rayon fromagerie."],"female_lines":[]}]},{"id":13,"section":"C","theme":"Public announcement - Museum","question":"Pourquoi le musée est-il fermé ?","options":[{"id":"A","text":"Rénovations en cours","image_prompt":""},{"id":"B","text":"Jour férié","image_prompt":""},{"id":"C","text":"Grève du personnel","image_prompt":""},{"id":"D","text":"Préparation d'une nouvelle exposition","image_prompt":""}],"correct":0,"transcript_fr":"Le Musée des Beaux-Arts vous informe que les galeries du deuxième étage sont temporairement fermées au public pour cause de rénovations majeures. Ces travaux dureront trois semaines. L'accès aux collections permanentes du rez-de-chaussée et du premier étage reste toutefois possible durant cette période.","transcript_en":"The Museum of Fine Arts informs you that the second-floor galleries are temporarily closed to the public due to major renovations. These works will last three weeks. Access to the permanent collections on the ground floor and first floor remains possible during this period.","points":[{"point":1,"male_lines":["Le Musée des Beaux-Arts vous informe que les galeries du deuxième étage sont temporairement fermées au public pour cause de rénovations majeures."],"female_lines":[]},{"point":2,"male_lines":["Ces travaux dureront trois semaines."],"female_lines":[]},{"point":3,"male_lines":["L'accès aux collections permanentes du rez-de-chaussée et du premier étage reste toutefois possible durant cette période."],"female_lines":[]}]},{"id":14,"section":"C","theme":"Public announcement - Airport","question":"Que doivent faire les passagers du vol 237 ?","options":[{"id":"A","text":"Procéder à l'embarquement immédiat","image_prompt":""},{"id":"B","text":"Rester près de la porte d'embarquement","image_prompt":""},{"id":"C","text":"Se présenter au comptoir d'enregistrement","image_prompt":""},{"id":"D","text":"Attendre une nouvelle annonce","image_prompt":""}],"correct":1,"transcript_fr":"Attention passagers du vol Air Canada 237 à destination de Vancouver. Nous vous prions de rester à proximité de la porte 24. L'embarquement débutera dans environ vingt minutes. Merci de préparer votre carte d'embarquement et une pièce d'identité valide.","transcript_en":"Attention passengers of Air Canada flight 237 to Vancouver. Please stay near gate 24. Boarding will begin in about twenty minutes. Please prepare your boarding pass and a valid ID.","points":[{"point":1,"male_lines":["Attention passagers du vol Air Canada 237 à destination de Vancouver."],"female_lines":[]},{"point":2,"male_lines":["Nous vous prions de rester à proximité de la porte 24."],"female_lines":[]},{"point":3,"male_lines":["L'embarquement débutera dans environ vingt minutes."],"female_lines":[]},{"point":4,"male_lines":["Merci de préparer votre carte d'embarquement et une pièce d'identité valide."],"female_lines":[]}]},{"id":15,"section":"C","theme":"Public announcement - Library","question":"Quel changement est annoncé ?","options":[{"id":"A","text":"Nouveaux horaires d'ouverture","image_prompt":""},{"id":"B","text":"Fermeture temporaire","image_prompt":""},{"id":"C","text":"Déménagement des sections","image_prompt":""},{"id":"D","text":"Modification du règlement","image_prompt":""}],"correct":0,"transcript_fr":"La bibliothèque municipale informe ses usagers que de nouveaux horaires d'ouverture entreront en vigueur dès le premier janvier. Désormais, nous serons ouverts du mardi au samedi de 9h à 18h, et fermés le dimanche et lundi. Ces nouveaux horaires permettront d'optimiser nos services.","transcript_en":"The municipal library informs its users that new opening hours will take effect from January 1st. From now on, we will be open Tuesday through Saturday from 9 AM to 6 PM, and closed Sunday and Monday. These new hours will allow us to optimize our services.","points":[{"point":1,"male_lines":["La bibliothèque municipale informe ses usagers que de nouveaux horaires d'ouverture entreront en vigueur dès le premier janvier."],"female_lines":[]},{"point":2,"male_lines":["Désormais, nous serons ouverts du mardi au samedi de 9h à 18h, et fermés le dimanche et lundi."],"female_lines":[]},{"point":3,"male_lines":["Ces nouveaux horaires permettront d'optimiser nos services."],"female_lines":[]}]},{"id":16,"section":"C","theme":"Public announcement - Weather alert","question":"Quel temps est annoncé ?","options":[{"id":"A","text":"Tempête de neige","image_prompt":""},{"id":"B","text":"Pluie verglaçante","image_prompt":""},{"id":"C","text":"Vents violents","image_prompt":""},{"id":"D","text":"Canicule","image_prompt":""}],"correct":0,"transcript_fr":"Avis de tempête hivernale pour la région de Montréal. De fortes chutes de neige sont attendues dès ce soir et persisteront jusqu'à demain midi. Accumulation prévue de 25 à 30 centimètres. Les conditions routières seront difficiles. Évitez les déplacements non essentiels.","transcript_en":"Winter storm warning for the Montreal region. Heavy snowfall is expected from this evening and will persist until noon tomorrow. Expected accumulation of 25 to 30 centimeters. Road conditions will be difficult. Avoid non-essential travel.","points":[{"point":1,"male_lines":["Avis de tempête hivernale pour la région de Montréal."],"female_lines":[]},{"point":2,"male_lines":["De fortes chutes de neige sont attendues dès ce soir et persisteront jusqu'à demain midi."],"female_lines":[]},{"point":3,"male_lines":["Accumulation prévue de 25 à 30 centimètres. Les conditions routières seront difficiles."],"female_lines":[]},{"point":4,"male_lines":["Évitez les déplacements non essentiels."],"female_lines":[]}]},{"id":17,"section":"D","theme":"Short dialogue - Making plans","question":"Quelle est l'intention du premier locuteur ?","options":[{"id":"A","text":"Proposer une sortie","image_prompt":""},{"id":"B","text":"Refuser une invitation","image_prompt":""},{"id":"C","text":"Demander un conseil","image_prompt":""},{"id":"D","text":"Se plaindre du temps","image_prompt":""}],"correct":0,"transcript_fr":"Homme: Ça te dirait d'aller voir le nouveau film au cinéma ce soir? Femme: Oh, je ne sais pas, j'ai beaucoup de travail. Homme: Allez, tu as besoin de te détendre un peu. Femme: Tu as raison, pourquoi pas? À quelle heure?","transcript_en":"Man: Would you like to go see the new movie at the cinema tonight? Woman: Oh, I don't know, I have a lot of work. Man: Come on, you need to relax a bit. Woman: You're right, why not? What time?","points":[{"point":1,"male_lines":["Ça te dirait d'aller voir le nouveau film au cinéma ce soir?","Allez, tu as besoin de te détendre un peu."],"female_lines":["Oh, je ne sais pas, j'ai beaucoup de travail.","Tu as raison, pourquoi pas? À quelle heure?"]},{"point":2,"male_lines":["Je pensais à la séance de 19h30."],"female_lines":["C'est parfait, ça me laisse le temps de finir mon travail."]},{"point":3,"male_lines":["Je passe te chercher à 19h alors?"],"female_lines":["Oui, super, je serai prête à ce moment-là."]},{"point":4,"male_lines":["Génial, à ce soir alors!"],"female_lines":["À ce soir, merci pour l'invitation!"]}]},{"id":18,"section":"D","theme":"Short dialogue - Complaint","question":"Pourquoi la femme appelle-t-elle ?","options":[{"id":"A","text":"Pour commander un produit","image_prompt":""},{"id":"B","text":"Pour se plaindre d'un service","image_prompt":""},{"id":"C","text":"Pour demander des informations","image_prompt":""},{"id":"D","text":"Pour annuler une commande","image_prompt":""}],"correct":1,"transcript_fr":"Femme: Bonjour, je vous appelle parce que mon lave-vaisselle ne fonctionne plus après seulement deux mois. Homme: Je suis désolé madame, quelle est la nature du problème? Femme: Il ne démarre plus du tout, plus aucun voyant ne s'allume. Homme: Je comprends, je vais organiser une intervention sous garantie.","transcript_en":"Woman: Hello, I'm calling because my dishwasher no longer works after only two months. Man: I'm sorry ma'am, what is the nature of the problem? Woman: It won't start at all anymore, no lights come on. Man: I understand, I will arrange a warranty repair.","points":[{"point":1,"male_lines":["Je suis désolé madame, quelle est la nature du problème?","Je comprends, je vais organiser une intervention sous garantie."],"female_lines":["Bonjour, je vous appelle parce que mon lave-vaisselle ne fonctionne plus après seulement deux mois.","Il ne démarre plus du tout, plus aucun voyant ne s'allume."]},{"point":2,"male_lines":["Quand avez-vous acheté cet appareil exactement?"],"female_lines":["Je l'ai acheté en décembre dernier, il est encore sous garantie."]},{"point":3,"male_lines":["Oui, tout à fait. Un technicien peut passer jeudi prochain."],"female_lines":["Jeudi me convient parfaitement, entre 14h et 16h si possible."]},{"point":4,"male_lines":["Je note votre préférence, le technicien vous appellera avant de venir."],"female_lines":["Merci beaucoup, j'attends votre appel avec impatience."]}]},{"id":19,"section":"D","theme":"Short dialogue - Requesting information","question":"Que veut savoir l'homme ?","options":[{"id":"A","text":"Le prix d'un article","image_prompt":""},{"id":"B","text":"La disponibilité d'un produit","image_prompt":""},{"id":"C","text":"Les heures d'ouverture","image_prompt":""},{"id":"D","text":"L'adresse du magasin","image_prompt":""}],"correct":1,"transcript_fr":"Homme: Bonjour, est-ce que vous avez encore le modèle XR-200 en stock? Femme: Un instant monsieur, je vérifie. Non, nous sommes en rupture de stock. Homme: Quand est-ce que vous en recevrez? Femme: La prochaine livraison est prévue pour la semaine prochaine.","transcript_en":"Man: Hello, do you still have the XR-200 model in stock? Woman: One moment sir, I'll check. No, we are out of stock. Man: When will you receive more? Woman: The next delivery is scheduled for next week.","points":[{"point":1,"male_lines":["Bonjour, est-ce que vous avez encore le modèle XR-200 en stock?","Quand est-ce que vous en recevrez?"],"female_lines":["Un instant monsieur, je vérifie. Non, nous sommes en rupture de stock.","La prochaine livraison est prévue pour la semaine prochaine."]},{"point":2,"male_lines":["Puis-je le réserver pour être sûr d'en avoir un?"],"female_lines":["Oui, je peux prendre votre nom et votre numéro de téléphone."]},{"point":3,"male_lines":["C'est Marc Tremblay, mon numéro est le 514-555-0123."],"female_lines":["Parfait, je vous appelle dès que le colis arrive."]},{"point":4,"male_lines":["Merci beaucoup pour votre aide."],"female_lines":["Je vous en prie, bonne journée monsieur Tremblay."]}]},{"id":20,"section":"D","theme":"Short dialogue - Giving advice","question":"Quel conseil la femme donne-t-elle ?","options":[{"id":"A","text":"Prendre des vacances","image_prompt":""},{"id":"B","text":"Consulter un médecin","image_prompt":""},{"id":"C","text":"Faire du sport","image_prompt":""},{"id":"D","text":"Changer de travail","image_prompt":""}],"correct":2,"transcript_fr":"Homme: Je suis tellement fatigué en ce moment, je ne sais pas quoi faire. Femme: Tu devrais essayer de faire du sport régulièrement, ça aide beaucoup. Homme: Tu crois? Je n'ai jamais été très sportif. Femme: Commence doucement, avec la marche ou la natation.","transcript_en":"Man: I'm so tired lately, I don't know what to do. Woman: You should try exercising regularly, it helps a lot. Man: You think so? I've never been very athletic. Woman: Start slowly, with walking or swimming.","points":[{"point":1,"male_lines":["Je suis tellement fatigué en ce moment, je ne sais pas quoi faire.","Tu crois? Je n'ai jamais été très sportif."],"female_lines":["Tu devrais essayer de faire du sport régulièrement, ça aide beaucoup.","Commence doucement, avec la marche ou la natation."]},{"point":2,"male_lines":["La natation me semble accessible, il y a une piscine près de chez moi."],"female_lines":["C'est parfait, l'eau est excellente pour le corps et l'esprit."]},{"point":3,"male_lines":["Tu as raison, je vais m'inscrire dès demain."],"female_lines":["Tu verras, après quelques semaines tu te sentiras beaucoup mieux."]},{"point":4,"male_lines":["Merci pour ce conseil, j'espère que ça marchera."],"female_lines":["N'hésite pas à me dire comment ça se passe!"]}]},{"id":21,"section":"D","theme":"Short dialogue - Expressing opinion","question":"Quelle est l'opinion de l'homme ?","options":[{"id":"A","text":"Le restaurant est trop cher","image_prompt":""},{"id":"B","text":"La nourriture est excellente","image_prompt":""},{"id":"C","text":"Le service est trop lent","image_prompt":""},{"id":"D","text":"L'ambiance est trop bruyante","image_prompt":""}],"correct":3,"transcript_fr":"Femme: Alors, qu'est-ce que tu penses de ce nouveau restaurant? Homme: La cuisine est bonne, mais je trouve qu'il y a trop de bruit. Femme: Oui, c'est vrai qu'on doit presque crier pour se parler. Homme: Exactement, je préfère les endroits plus calmes pour dîner.","transcript_en":"Woman: So, what do you think of this new restaurant? Man: The food is good, but I find it too noisy. Woman: Yes, it's true we almost have to shout to talk to each other. Man: Exactly, I prefer quieter places for dinner.","points":[{"point":1,"male_lines":["La cuisine est bonne, mais je trouve qu'il y a trop de bruit.","Exactement, je préfère les endroits plus calmes pour dîner."],"female_lines":["Alors, qu'est-ce que tu penses de ce nouveau restaurant?","Oui, c'est vrai qu'on doit presque crier pour se parler."]},{"point":2,"male_lines":["J'ai mal à la tête à cause du volume de la musique."],"female_lines":["Je comprends, ce n'est pas très agréable pour une conversation."]},{"point":3,"male_lines":["On devrait essayer le restaurant italien de la rue suivante la prochaine fois."],"female_lines":["Bonne idée, j'ai entendu dire que l'ambiance y est plus feutrée."]},{"point":4,"male_lines":["Parfait, on réserve pour samedi prochain alors?"],"female_lines":["Avec plaisir, j'ai hâte de découvrir cet endroit."]}]},{"id":22,"section":"D","theme":"Short dialogue - Making a suggestion","question":"Que suggère la femme ?","options":[{"id":"A","text":"Aller au cinéma","image_prompt":""},{"id":"B","text":"Faire une randonnée","image_prompt":""},{"id":"C","text":"Visiter un musée","image_prompt":""},{"id":"D","text":"Organiser un pique-nique","image_prompt":""}],"correct":3,"transcript_fr":"Femme: Il fait tellement beau aujourd'hui, on devrait profiter de l'extérieur. Homme: Tu as raison, on pourrait aller au parc. Femme: Mieux encore, je propose qu'on fasse un pique-nique près du lac. Homme: Excellente idée, j'achète des sandwichs et du jus de fruits.","transcript_en":"Woman: It's so beautiful today, we should take advantage of being outside. Man: You're right, we could go to the park. Woman: Even better, I suggest we have a picnic near the lake. Man: Excellent idea, I'll buy sandwiches and fruit juice.","points":[{"point":1,"male_lines":["Tu as raison, on pourrait aller au parc.","Excellente idée, j'achète des sandwichs et du jus de fruits."],"female_lines":["Il fait tellement beau aujourd'hui, on devrait profiter de l'extérieur.","Mieux encore, je propose qu'on fasse un pique-nique près du lac."]},{"point":2,"male_lines":["Je vais préparer une salade de fruits frais aussi."],"female_lines":["Super, j'apporterai une couverture et des serviettes."]},{"point":3,"male_lines":["On se retrouve devant chez toi dans une heure?"],"female_lines":["Parfait, j'aurai le temps de préparer quelques desserts."]},{"point":4,"male_lines":["Génial, ça va être une belle journée!"],"female_lines":["J'ai hâte d'être là-bas, le lac est magnifique en cette saison."]}]},{"id":23,"section":"E","theme":"Radio interview - Environment","question":"Selon l'invité, quel est le principal problème environnemental ?","options":[{"id":"A","text":"La pollution de l'air","image_prompt":""},{"id":"B","text":"Le réchauffement climatique","image_prompt":""},{"id":"C","text":"La déforestation","image_prompt":""},{"id":"D","text":"La gestion des déchets","image_prompt":""}],"correct":1,"transcript_fr":"Présentatrice: Bonjour et bienvenue à notre émission. Aujourd'hui nous recevons le Dr Martin, expert en environnement. Dr Martin: Bonjour, merci de m'accueillir. Présentatrice: Selon vous, quel est le défi le plus urgent? Dr Martin: Sans aucun doute, le réchauffement climatique. Les températures augmentent à un rythme alarmant.","transcript_en":"Presenter: Hello and welcome to our show. Today we welcome Dr. Martin, environmental expert. Dr. Martin: Hello, thank you for having me. Presenter: In your opinion, what is the most urgent challenge? Dr. Martin: Without a doubt, global warming. Temperatures are rising at an alarming rate.","points":[{"point":1,"male_lines":["Bonjour, merci de m'accueillir.","Sans aucun doute, le réchauffement climatique. Les températures augmentent à un rythme alarmant."],"female_lines":["Bonjour et bienvenue à notre émission. Aujourd'hui nous recevons le Dr Martin, expert en environnement.","Selon vous, quel est le défi le plus urgent?"]},{"point":2,"male_lines":["Nous observons des canicules de plus en plus fréquentes et intenses."],"female_lines":["Quelles sont les conséquences concrètes pour la population québécoise?"]},{"point":3,"male_lines":["Les inondations printanières deviennent plus sévères et les récoltes sont menacées."],"female_lines":["Existe-t-il des solutions concrètes à notre portée?"]},{"point":4,"male_lines":["Absolument, la transition énergétique et la réduction des émissions de carbone sont essentielles."],"female_lines":["Merci docteur Martin pour ces informations précieuses."]}]},{"id":24,"section":"E","theme":"Radio interview - Health","question":"Quel conseil l'expert donne-t-il pour mieux dormir ?","options":[{"id":"A","text":"Prendre des médicaments","image_prompt":""},{"id":"B","text":"Éviter les écrans le soir","image_prompt":""},{"id":"C","text":"Faire une sieste l'après-midi","image_prompt":""},{"id":"D","text":"Manger plus léger","image_prompt":""}],"correct":1,"transcript_fr":"Journaliste: Docteur Lefebvre, beaucoup de gens se plaignent de troubles du sommeil. Que recommandez-vous? Docteur: Premièrement, il faut éviter absolument les écrans une heure avant le coucher. Journaliste: Les téléphones et tablettes? Docteur: Exactement, la lumière bleue perturbe la mélatonine.","transcript_en":"Journalist: Dr. Lefebvre, many people complain about sleep disorders. What do you recommend? Doctor: First, you must absolutely avoid screens one hour before bedtime. Journalist: Phones and tablets? Doctor: Exactly, blue light disrupts melatonin.","points":[{"point":1,"male_lines":["Premièrement, il faut éviter absolument les écrans une heure avant le coucher.","Exactement, la lumière bleue perturbe la mélatonine."],"female_lines":["Docteur Lefebvre, beaucoup de gens se plaignent de troubles du sommeil. Que recommandez-vous?","Les téléphones et tablettes?"]},{"point":2,"male_lines":["Il faut aussi privilégier une chambre fraîche et bien obscurcie."],"female_lines":["Et concernant l'alimentation, y a-t-il des précautions à prendre?"]},{"point":3,"male_lines":["Oui, éviter les repas copieux et la caféine après 16 heures."],"female_lines":["Combien d'heures de sommeil faut-il idéalement?"]},{"point":4,"male_lines":["Entre sept et neuf heures selon les besoins individuels."],"female_lines":["Merci docteur pour ces conseils pratiques."]}]},{"id":25,"section":"E","theme":"Radio interview - Technology","question":"Quelle est l'innovation présentée ?","options":[{"id":"A","text":"Une voiture électrique","image_prompt":""},{"id":"B","text":"Un smartphone pliable","image_prompt":""},{"id":"C","text":"Un assistant vocal intelligent","image_prompt":""},{"id":"D","text":"Des lunettes réalité augmentée","image_prompt":""}],"correct":3,"transcript_fr":"Animateur: Aujourd'hui nous testons les nouvelles lunettes à réalité augmentée. Ingénieur: Ces lunettes permettent de voir des informations en surimpression sur le monde réel. Animateur: Comment fonctionnent-elles exactement? Ingénieur: Des capteurs analysent l'environnement et projettent des données pertinentes.","transcript_en":"Host: Today we're testing the new augmented reality glasses. Engineer: These glasses allow you to see information overlaid on the real world. Host: How exactly do they work? Engineer: Sensors analyze the environment and project relevant data.","points":[{"point":1,"male_lines":["Ces lunettes permettent de voir des informations en surimpression sur le monde réel.","Des capteurs analysent l'environnement et projettent des données pertinentes."],"female_lines":["Aujourd'hui nous testons les nouvelles lunettes à réalité augmentée.","Comment fonctionnent-elles exactement?"]},{"point":2,"male_lines":["Par exemple, vous pouvez voir la navigation GPS directement dans votre champ de vision."],"female_lines":["C'est impressionnant, mais est-ce confortable à porter?"]},{"point":3,"male_lines":["Elles sont légères et s'ajustent à la forme de votre visage."],"female_lines":["Quelles sont les applications professionnelles possibles?"]},{"point":4,"male_lines":["Les médecins peuvent voir les dossiers patients pendant l'opération."],"female_lines":["Une révolution technologique en effet, merci pour cette démonstration."]}]},{"id":26,"section":"E","theme":"Radio interview - Culture","question":"Quel est le sujet principal de l'entrevue ?","options":[{"id":"A","text":"Un nouveau film québécois","image_prompt":""},{"id":"B","text":"Un festival de musique","image_prompt":""},{"id":"C","text":"Une exposition d'art contemporain","image_prompt":""},{"id":"D","text":"Un livre primé","image_prompt":""}],"correct":0,"transcript_fr":"Animatrice: Nous avons le plaisir de recevoir le réalisateur Jean-François Rivard. Réalisateur: Merci d'être ici. Animatrice: Votre nouveau film 'Les Saisons' sort cette semaine. Réalisateur: Oui, c'est un drame familial qui se déroule dans les Cantons-de-l'Est.","transcript_en":"Host: We have the pleasure of welcoming director Jean-François Rivard. Director: Thank you for having me. Host: Your new film 'The Seasons' is coming out this week. Director: Yes, it's a family drama set in the Eastern Townships.","points":[{"point":1,"male_lines":["Merci d'être ici.","Oui, c'est un drame familial qui se déroule dans les Cantons-de-l'Est."],"female_lines":["Nous avons le plaisir de recevoir le réalisateur Jean-François Rivard.","Votre nouveau film 'Les Saisons' sort cette semaine."]},{"point":2,"male_lines":["J'ai voulu capturer la beauté des paysages québécois en toutes saisons."],"female_lines":["Le casting semble exceptionnel, comment avez-vous choisi vos acteurs?"]},{"point":3,"male_lines":["J'ai privilégié des talents locaux pour donner une authenticité particulière."],"female_lines":["Le film a déjà reçu plusieurs prix dans des festivals internationaux."]},{"point":4,"male_lines":["Oui, c'était une belle surprise et une reconnaissance du cinéma québécois."],"female_lines":["Nous vous souhaitons beaucoup de succès pour la sortie en salle."]}]},{"id":27,"section":"F","theme":"Discussion - Housing","question":"Quelle est l'opinion de la femme sur l'appartement ?","options":[{"id":"A","text":"Il est trop petit","image_prompt":""},{"id":"B","text":"Il est trop cher","image_prompt":""},{"id":"C","text":"Il est parfait pour eux","image_prompt":""},{"id":"D","text":"Il est trop éloigné du centre","image_prompt":""}],"correct":2,"transcript_fr":"Homme: J'ai visité cet appartement sur la rue Saint-Denis, il est vraiment bien. Femme: Raconte-moi, il fait combien de pièces? Homme: Deux chambres, une cuisine moderne et un grand salon. Femme: C'est exactement ce qu'il nous faut pour notre famille!","transcript_en":"Man: I visited this apartment on Saint-Denis street, it's really nice. Woman: Tell me, how many rooms does it have? Man: Two bedrooms, a modern kitchen and a large living room. Woman: It's exactly what we need for our family!","points":[{"point":1,"male_lines":["J'ai visité cet appartement sur la rue Saint-Denis, il est vraiment bien.","Deux chambres, une cuisine moderne et un grand salon."],"female_lines":["Raconte-moi, il fait combien de pièces?","C'est exactement ce qu'il nous faut pour notre famille!"]},{"point":2,"male_lines":["Et il y a même une petite terrasse avec vue sur le parc."],"female_lines":["C'est idéal pour les enfants, ils pourront jouer dehors."]},{"point":3,"male_lines":["Le loyer est un peu élevé mais raisonnable pour le quartier."],"female_lines":["On peut le négocier, surtout si on signe un bail de deux ans."]},{"point":4,"male_lines":["Bonne idée, je vais contacter le propriétaire demain."],"female_lines":["Parfait, j'ai hâte de visiter cet endroit avec toi."]}]},{"id":28,"section":"F","theme":"Discussion - Travel plans","question":"Où veut aller l'homme ?","options":[{"id":"A","text":"À Paris","image_prompt":""},{"id":"B","text":"À Tokyo","image_prompt":""},{"id":"C","text":"À Rome","image_prompt":""},{"id":"D","text":"À Barcelone","image_prompt":""}],"correct":1,"transcript_fr":"Femme: Pour nos vacances cet été, tu as une idée de destination? Homme: Je rêve d'aller au Japon, découvrir Tokyo et la culture japonaise. Femme: C'est loin et ça coûte cher non? Homme: Oui, mais c'est une expérience unique que je veux vivre une fois dans ma vie.","transcript_en":"Woman: For our vacation this summer, do you have a destination in mind? Man: I dream of going to Japan, discovering Tokyo and Japanese culture. Woman: It's far and expensive, isn't it? Man: Yes, but it's a unique experience I want to have once in my life.","points":[{"point":1,"male_lines":["Je rêve d'aller au Japon, découvrir Tokyo et la culture japonaise.","Oui, mais c'est une expérience unique que je veux vivre une fois dans ma vie."],"female_lines":["Pour nos vacances cet été, tu as une idée de destination?","C'est loin et ça coûte cher non?"]},{"point":2,"male_lines":["On pourrait économiser pendant six mois pour se le permettre."],"female_lines":["Tu as raison, et le Japon est sûrement magnifique en été."]},{"point":3,"male_lines":["On pourrait visiter Kyoto aussi, avec ses temples anciens."],"female_lines":["J'adore l'idée, commençons à planifier notre itinéraire."]},{"point":4,"male_lines":["Je vais chercher des billets d'avion dès ce soir."],"female_lines":["Parfait, je vais regarder les hôtels traditionnels japonais."]}]},{"id":29,"section":"F","theme":"Discussion - Work-life balance","question":"Quel problème discutent les locuteurs ?","options":[{"id":"A","text":"Le manque de temps libre","image_prompt":""},{"id":"B","text":"Les conflits avec des collègues","image_prompt":""},{"id":"C","text":"La distance pour se rendre au travail","image_prompt":""},{"id":"D","text":"Le salaire insuffisant","image_prompt":""}],"correct":0,"transcript_fr":"Femme: Je ne sais plus quoi faire, je travaille soixante heures par semaine. Homme: C'est trop, tu n'as aucun moment pour toi. Femme: Exactement, je rentre épuisée et je n'ai plus de vie sociale. Homme: Tu devrais parler à ton patron pour réduire tes heures.","transcript_en":"Woman: I don't know what to do anymore, I work sixty hours a week. Man: That's too much, you don't have any time for yourself. Woman: Exactly, I come home exhausted and I have no social life. Man: You should talk to your boss about reducing your hours.","points":[{"point":1,"male_lines":["C'est trop, tu n'as aucun moment pour toi.","Tu devrais parler à ton patron pour réduire tes heures."],"female_lines":["Je ne sais plus quoi faire, je travaille soixante heures par semaine.","Exactement, je rentre épuisée et je n'ai plus de vie sociale."]},{"point":2,"male_lines":["Ton bien-être est plus important que n'importe quel travail."],"female_lines":["J'ai peur de perdre mon emploi si je me plains."]},{"point":3,"male_lines":["Une entreprise responsable comprendra que tu risques le burn-out."],"female_lines":["Tu as raison, je vais demander un rendez-vous avec le directeur."]},{"point":4,"male_lines":["Propose un télétravail partiel, ça pourrait être une solution."],"female_lines":["Excellente idée, ça me permettrait de mieux gérer mon temps."]}]},{"id":30,"section":"F","theme":"Discussion - Education","question":"Quelle solution proposent-ils pour améliorer l'éducation ?","options":[{"id":"A","text":"Réduire le nombre d'élèves par classe","image_prompt":""},{"id":"B","text":"Augmenter les salaires des enseignants","image_prompt":""},{"id":"C","text":"Introduire plus de technologie","image_prompt":""},{"id":"D","text":"Ajouter des activités sportives","image_prompt":""}],"correct":0,"transcript_fr":"Homme: Les classes sont surchargées, certains profs ont trente-cinq élèves. Femme: C'est impossible de bien enseigner avec autant d'élèves. Homme: Exactement, il faudrait limiter à vingt élèves maximum par classe. Femme: Je suis d'accord, chaque enfant aurait plus d'attention.","transcript_en":"Man: Classes are overcrowded, some teachers have thirty-five students. Woman: It's impossible to teach well with so many students. Man: Exactly, we should limit it to twenty students maximum per class. Woman: I agree, each child would get more attention.","points":[{"point":1,"male_lines":["Les classes sont surchargées, certains profs ont trente-cinq élèves.","Exactement, il faudrait limiter à vingt élèves maximum par classe."],"female_lines":["C'est impossible de bien enseigner avec autant d'élèves.","Je suis d'accord, chaque enfant aurait plus d'attention."]},{"point":2,"male_lines":["Il faudrait aussi recruter plus d'enseignants qualifiés."],"female_lines":["Mais ça coûte cher, d'où viendrait l'argent?"]},{"point":3,"male_lines":["On pourrait réduire les dépenses administratives superflues."],"female_lines":["C'est une piste intéressante, il faut revoir les priorités budgétaires."]},{"point":4,"male_lines":["L'éducation devrait être la priorité absolue de notre société."],"female_lines":["Tout à fait, nos enfants sont l'avenir du Québec."]}]},{"id":31,"section":"G","theme":"Debate - Remote work","question":"Quel est l'argument principal contre le télétravail présenté dans le dialogue ?","options":[{"id":"A","text":"La baisse de productivité","image_prompt":""},{"id":"B","text":"L'isolement social des employés","image_prompt":""},{"id":"C","text":"Les coûts élevés pour l'entreprise","image_prompt":""},{"id":"D","text":"La difficulté de supervision","image_prompt":""}],"correct":1,"transcript_fr":"Modérateur: Bienvenue à notre débat sur le télétravail. Monsieur Dubois, vous êtes contre? Dubois: Oui, car l'isolement social est dramatique pour les employés. Modératrice: Madame Lavoie, votre réponse? Lavoie: Je comprends, mais la flexibilité vaut ce sacrifice. Dubois: Non, la santé mentale ne doit pas être négociée. Lavoie: Les entreprises peuvent organiser des rencontres régulières. Dubois: Ce n'est pas suffisant, le contact humain quotidien est essentiel. Lavoie: Les employés gagnent deux heures de transport par jour. Dubois: Mais ils perdent le lien avec leurs collègues. Lavoie: Le compromis serait le hybride, trois jours au bureau. Dubois: C'est acceptable, mais pas le full remote.","transcript_en":"Moderator: Welcome to our debate on remote work. Mr. Dubois, you are against? Dubois: Yes, because social isolation is dramatic for employees. Moderator: Ms. Lavoie, your response? Lavoie: I understand, but flexibility is worth this sacrifice. Dubois: No, mental health should not be negotiated. Lavoie: Companies can organize regular meetings. Dubois: It's not enough, daily human contact is essential. Lavoie: Employees save two hours of commuting per day. Dubois: But they lose connection with their colleagues. Lavoie: The compromise would be hybrid, three days in the office. Dubois: That's acceptable, but not full remote.","points":[{"point":1,"male_lines":["Bienvenue à notre débat sur le télétravail. Monsieur Dubois, vous êtes contre?","Oui, car l'isolement social est dramatique pour les employés.","Non, la santé mentale ne doit pas être négociée."],"female_lines":["Madame Lavoie, votre réponse?","Je comprends, mais la flexibilité vaut ce sacrifice."]},{"point":2,"male_lines":["Ce n'est pas suffisant, le contact humain quotidien est essentiel."],"female_lines":["Les entreprises peuvent organiser des rencontres régulières."]},{"point":3,"male_lines":["Mais ils perdent le lien avec leurs collègues."],"female_lines":["Les employés gagnent deux heures de transport par jour."]},{"point":4,"male_lines":["C'est acceptable, mais pas le full remote."],"female_lines":["Le compromis serait le hybride, trois jours au bureau."]},{"point":5,"male_lines":["Le bureau favorise la collaboration spontanée et l'innovation."],"female_lines":["Les outils numériques permettent une collaboration efficace à distance."]},{"point":6,"male_lines":["Rien ne remplace le brainstorming en personne."],"female_lines":["Les vidéoconférences peuvent être tout aussi productives."]},{"point":7,"male_lines":["Les jeunes employés ont besoin de mentorat présentiel."],"female_lines":["Le mentorat peut se faire efficacement en ligne avec les bons outils."]},{"point":8,"male_lines":["La culture d'entreprise s'efface sans présence physique."],"female_lines":["La culture se transmet par les valeurs partagées, pas seulement par le lieu."]},{"point":9,"male_lines":["Les réunions virtuelles créent de la fatigue et du désengagement."],"female_lines":["Elles permettent d'inclure des talents de partout dans le monde."]},{"point":10,"male_lines":["Je maintiens que le présentiel reste nécessaire pour l'équipe."],"female_lines":["Et je défends l'autonomie et la qualité de vie des travailleurs."]}]},{"id":32,"section":"G","theme":"Debate - Immigration","question":"Quelle est la position de la femme sur l'immigration au Québec ?","options":[{"id":"A","text":"Elle veut la réduire drastiquement","image_prompt":""},{"id":"B","text":"Elle soutient une immigration sélective","image_prompt":""},{"id":"C","text":"Elle défend une immigration accrue","image_prompt":""},{"id":"D","text":"Elle propose un moratoire temporaire","image_prompt":""}],"correct":2,"transcript_fr":"Animateur: Débat sur l'immigration au Québec. Madame Chen, votre position? Chen: Nous devons accueillir plus d'immigrants, notre économie en dépend. Animateur: Monsieur Gagnon? Gagnon: Non, ça met en péril notre identité francophone. Chen: Au contraire, les immigrants apprennent le français avec enthousiasme. Gagnon: Les chiffres montrent une baisse du français. Chen: C'est faux, 85% adoptent le français comme langue commune. Gagnon: Les services sociaux sont saturés. Chen: L'immigration finance ces services par les impôts payés. Gagnon: Les Québécois de souche sont exclus. Chen: Nous sommes tous Québécois, peu importe nos origines. Gagnon: La intégration échoue dans certains quartiers. Chen: Investissons en éducation et en francisation alors. Gagnon: C'est coûteux et inefficace. Chen: C'est un investissement dans notre avenir collectif.","transcript_en":"Host: Debate on immigration in Quebec. Ms. Chen, your position? Chen: We must welcome more immigrants, our economy depends on it. Host: Mr. Gagnon? Gagnon: No, it endangers our French-speaking identity. Chen: On the contrary, immigrants learn French enthusiastically. Gagnon: The numbers show a decline in French. Chen: That's false, 85% adopt French as a common language. Gagnon: Social services are saturated. Chen: Immigration funds these services through taxes paid. Gagnon: Old-stock Quebecers are excluded. Chen: We are all Quebecers, regardless of our origins. Gagnon: Integration fails in some neighborhoods. Chen: Let's invest in education and francization then. Gagnon: It's costly and ineffective. Chen: It's an investment in our collective future.","points":[{"point":1,"male_lines":["Débat sur l'immigration au Québec. Madame Chen, votre position?","Non, ça met en péril notre identité francophone.","Les chiffres montrent une baisse du français."],"female_lines":["Nous devons accueillir plus d'immigrants, notre économie en dépend.","Au contraire, les immigrants apprennent le français avec enthousiasme.","C'est faux, 85% adoptent le français comme langue commune."]},{"point":2,"male_lines":["Les services sociaux sont saturés."],"female_lines":["L'immigration finance ces services par les impôts payés."]},{"point":3,"male_lines":["Les Québécois de souche sont exclus."],"female_lines":["Nous sommes tous Québécois, peu importe nos origines."]},{"point":4,"male_lines":["La intégration échoue dans certains quartiers."],"female_lines":["Investissons en éducation et en francisation alors."]},{"point":5,"male_lines":["C'est coûteux et inefficace."],"female_lines":["C'est un investissement dans notre avenir collectif."]},{"point":6,"male_lines":["Les emplois disparaissent au profit des immigrants."],"female_lines":["Les immigrants créent des emplois en démarrant des entreprises."]},{"point":7,"male_lines":["La langue française est menacée à Montréal."],"female_lines":["Le français progresse grâce à la politique de francisation."]},{"point":8,"male_lines":["Nous devons protéger notre héritage culturel unique."],"female_lines":["La diversité enrichit notre culture québécoise."]},{"point":9,"male_lines":["Les écoles sont débordées par l'arrivée des nouveaux élèves."],"female_lines":["Nos écoles ont besoin de plus de financement, pas moins d'élèves."]},{"point":10,"male_lines":["Je reste convaincu que nous devons ralentir l'immigration."],"female_lines":["Et je maintiens que le Québec a besoin de plus d'immigrants pour prospérer."]}]},{"id":33,"section":"G","theme":"Debate - Climate change","question":"Quelle solution le couple considère-t-il comme la plus urgente ?","options":[{"id":"A","text":"L'énergie nucléaire","image_prompt":""},{"id":"B","text":"Les énergies renouvelables","image_prompt":""},{"id":"C","text":"La réduction de la consommation","image_prompt":""},{"id":"D","text":"Les taxes carbone","image_prompt":""}],"correct":2,"transcript_fr":"Marie: Le réchauffement climatique s'accélère, il faut agir maintenant. Pierre: Je suis d'accord, mais par où commencer? Marie: La réduction de notre consommation est la clé. Pierre: Tu veux dire moins acheter? Marie: Exactement, moins de vêtements, moins de viande, moins de voyages en avion. Pierre: C'est difficile à mettre en place socialement. Marie: Il faut changer nos habitudes de vie radicalement. Pierre: Les énergies renouvelables ne suffisent pas? Marie: Elles aident, mais la surconsommation annule ces efforts. Pierre: Les politiciens ne veulent pas imposer ça. Marie: La société civile doit montrer l'exemple. Pierre: On commence par quoi chez nous? Marie: Tripler nos efforts de compostage et arrêter la voiture. Pierre: D'accord, je vais prendre le vélo pour aller travailler.","transcript_en":"Marie: Global warming is accelerating, we must act now. Pierre: I agree, but where to start? Marie: Reducing our consumption is the key. Pierre: You mean buying less? Marie: Exactly, fewer clothes, less meat, fewer plane trips. Pierre: It's difficult to implement socially. Marie: We must radically change our lifestyle habits. Pierre: Aren't renewable energies enough? Marie: They help, but overconsumption cancels out these efforts. Pierre: Politicians don't want to impose this. Marie: Civil society must set the example. Pierre: What do we start with at home? Marie: Triple our composting efforts and stop using the car. Pierre: Okay, I'll take the bike to work.","points":[{"point":1,"male_lines":["Je suis d'accord, mais par où commencer?","Tu veux dire moins acheter?"],"female_lines":["Le réchauffement climatique s'accélère, il faut agir maintenant.","La réduction de notre consommation est la clé."]},{"point":2,"male_lines":["C'est difficile à mettre en place socialement."],"female_lines":["Exactement, moins de vêtements, moins de viande, moins de voyages en avion."]},{"point":3,"male_lines":["Les énergies renouvelables ne suffisent pas?"],"female_lines":["Il faut changer nos habitudes de vie radicalement."]},{"point":4,"male_lines":["Les politiciens ne veulent pas imposer ça."],"female_lines":["Elles aident, mais la surconsommation annule ces efforts."]},{"point":5,"male_lines":["On commence par quoi chez nous?"],"female_lines":["La société civile doit montrer l'exemple."]},{"point":6,"male_lines":["D'accord, je vais prendre le vélo pour aller travailler."],"female_lines":["Tripler nos efforts de compostage et arrêter la voiture."]},{"point":7,"male_lines":["Je vais aussi réduire ma consommation de viande rouge."],"female_lines":["Parfait, chaque petit geste compte pour la planète."]},{"point":8,"male_lines":["Et si on installait des panneaux solaires sur le toit?"],"female_lines":["Excellente idée, on peut demander un devis cette semaine."]},{"point":9,"male_lines":["Il faut aussi sensibiliser nos amis et notre famille."],"female_lines":["Organisons un dîner pour discuter de ces changements."]},{"point":10,"male_lines":["Ensemble, on peut vraiment faire une différence significative."],"female_lines":["Absolument, l'avenir de nos enfants en dépend."]}]},{"id":34,"section":"G","theme":"Debate - Healthcare","question":"Quel est le principal problème du système de santé selon le dialogue ?","options":[{"id":"A","text":"Le manque de médecins","image_prompt":""},{"id":"B","text":"Les listes d'attente trop longues","image_prompt":""},{"id":"C","text":"Le financement insuffisant","image_prompt":""},{"id":"D","text":"La bureaucratie excessive","image_prompt":""}],"correct":1,"transcript_fr":"Docteur: Notre système de santé est en crise majeure. Patient: Je sais, j'attends depuis six mois pour mon opération. Docteur: Les listes d'attente sont devenues intolérables. Patient: Pourquoi ça prend autant de temps? Docteur: Manque de personnel et de ressources. Patient: Le gouvernement doit investir plus. Docteur: L'argent ne suffit pas, il faut réorganiser. Patient: Que proposez-vous concrètement? Docteur: Plus de chirurgies en privé pour dégorger le public. Patient: Ce n'est pas contre l'éthique? Docteur: Non, tant que c'est accessible à tous. Patient: Et les soins de prévention? Docteur: Essentiels, mais coûteux à long terme. Patient: Il faut choisir entre quoi et quoi? Docteur: Entre des soins rapides ou des soins universels gratuits.","transcript_en":"Doctor: Our healthcare system is in major crisis. Patient: I know, I've been waiting six months for my operation. Doctor: The waiting lists have become intolerable. Patient: Why does it take so long? Doctor: Lack of staff and resources. Patient: The government must invest more. Doctor: Money isn't enough, we need to reorganize. Patient: What do you propose specifically? Doctor: More private surgeries to relieve the public system. Patient: Isn't that against ethics? Doctor: No, as long as it's accessible to everyone. Patient: And preventive care? Doctor: Essential, but costly in the long term. Patient: We must choose between what and what? Doctor: Between fast care or free universal care.","points":[{"point":1,"male_lines":["Notre système de santé est en crise majeure.","Les listes d'attente sont devenues intolérables.","Manque de personnel et de ressources."],"female_lines":["Je sais, j'attends depuis six mois pour mon opération.","Pourquoi ça prend autant de temps?","Le gouvernement doit investir plus."]},{"point":2,"male_lines":["L'argent ne suffit pas, il faut réorganiser."],"female_lines":["Que proposez-vous concrètement?"]},{"point":3,"male_lines":["Plus de chirurgies en privé pour dégorger le public."],"female_lines":["Ce n'est pas contre l'éthique?"]},{"point":4,"male_lines":["Non, tant que c'est accessible à tous."],"female_lines":["Et les soins de prévention?"]},{"point":5,"male_lines":["Essentiels, mais coûteux à long terme."],"female_lines":["Il faut choisir entre quoi et quoi?"]},{"point":6,"male_lines":["Entre des soins rapides ou des soins universels gratuits."],"female_lines":["C'est un dilemme moral et économique difficile."]},{"point":7,"male_lines":["Le système actuel n'est plus viable financièrement."],"female_lines":["Les patients souffrent pendant que nous discutons."]},{"point":8,"male_lines":["Il faut des solutions innovantes et audacieuses."],"female_lines":["La technologie pourrait aider à réduire les délais."]},{"point":9,"male_lines":["Les téléconsultations sont une piste prometteuse."],"female_lines":["Mais elles ne remplacent pas les examens physiques."]},{"point":10,"male_lines":["Nous devons trouver un équilibre entre tradition et innovation."],"female_lines":["L'important est que chaque patient reçoive des soins dignes rapidement."]}]},{"id":35,"section":"G","theme":"Debate - Education reform","question":"Quelle réforme éducative est défendue par l'homme ?","options":[{"id":"A","text":"Plus d'heures de cours","image_prompt":""},{"id":"B","text":"Retour aux fondamentaux","image_prompt":""},{"id":"C","text":"Apprentissage par projet","image_prompt":""},{"id":"D","text":"Éducation bilingue obligatoire","image_prompt":""}],"correct":1,"transcript_fr":"Directeur: Nos élèves ne maîtrisent plus les bases. Enseignante: Que suggérez-vous comme changement? Directeur: Un retour aux fondamentaux: lecture, écriture, calcul. Enseignante: Mais l'apprentissage par projet est moderne. Directeur: Sans bases solides, les projets sont vides. Enseignante: Les enfants s'ennuient avec les méthodes traditionnelles. Directeur: La discipline et la rigueur ne font pas de mal. Enseignante: Il faut éveiller leur créativité aussi. Directeur: La créativité vient après la maîtrise technique. Enseignante: Et l'éducation sociale et émotionnelle? Directeur: Importante, mais secondaire face aux compétences académiques. Enseignante: Nous ne formons pas que des travailleurs. Directeur: Nous devons préparer des citoyens compétents. Enseignante: Des citoyens épanouis et critiques. Directeur: Commençons par leur donner les outils de base.","transcript_en":"Principal: Our students no longer master the basics. Teacher: What changes do you suggest? Principal: A return to fundamentals: reading, writing, math. Teacher: But project-based learning is modern. Principal: Without solid foundations, projects are empty. Teacher: Children get bored with traditional methods. Principal: Discipline and rigor don't hurt. Teacher: We must also awaken their creativity. Principal: Creativity comes after technical mastery. Teacher: And social and emotional education? Principal: Important, but secondary to academic skills. Teacher: We don't just train workers. Principal: We must prepare competent citizens. Teacher: Fulfilled and critical citizens. Principal: Let's start by giving them basic tools.","points":[{"point":1,"male_lines":["Nos élèves ne maîtrisent plus les bases.","Un retour aux fondamentaux: lecture, écriture, calcul.","Sans bases solides, les projets sont vides."],"female_lines":["Que suggérez-vous comme changement?","Mais l'apprentissage par projet est moderne.","Les enfants s'ennuient avec les méthodes traditionnelles."]},{"point":2,"male_lines":["La discipline et la rigueur ne font pas de mal."],"female_lines":["Il faut éveiller leur créativité aussi."]},{"point":3,"male_lines":["La créativité vient après la maîtrise technique."],"female_lines":["Et l'éducation sociale et émotionnelle?"]},{"point":4,"male_lines":["Importante, mais secondaire face aux compétences académiques."],"female_lines":["Nous ne formons pas que des travailleurs."]},{"point":5,"male_lines":["Nous devons préparer des citoyens compétents."],"female_lines":["Des citoyens épanouis et critiques."]},{"point":6,"male_lines":["Commençons par leur donner les outils de base."],"female_lines":["Mais ne négligeons pas leur développement personnel."]},{"point":7,"male_lines":["Les résultats aux examens standardisés sont en baisse constante."],"female_lines":["Les examens ne mesurent pas tout, surtout pas l'intelligence émotionnelle."]},{"point":8,"male_lines":["Nous devons être compétitifs au niveau international."],"female_lines":["La compétition ne devrait pas être notre seule priorité."]},{"point":9,"male_lines":["Les parents exigent des résultats concrets."],"female_lines":["Les parents veulent surtout des enfants heureux et équilibrés."]},{"point":10,"male_lines":["Trouvons un juste milieu entre exigence et bien-être."],"female_lines":["D'accord, mais ne sacrifions pas l'innovation pédagogique."]}]},{"id":36,"section":"H","theme":"Abstract discussion - Artificial intelligence ethics","question":"Quelle est la crainte principale exprimée concernant l'intelligence artificielle ?","options":[{"id":"A","text":"La perte d'emplois","image_prompt":""},{"id":"B","text":"La perte de contrôle humain","image_prompt":""},{"id":"C","text":"Les biais algorithmiques","image_prompt":""},{"id":"D","text":"La consommation énergétique","image_prompt":""}],"correct":1,"transcript_fr":"Philosophe: L'intelligence artificielle pose une question existentielle. Scientifique: Laquelle précisément? Philosophe: Celle de la perte de contrôle humain sur nos créations. Scientifique: Vous pensez aux scénarios de science-fiction? Philosophe: Non, à une délégation progressive et irréversible des décisions. Scientifique: Les algorithmes restent des outils. Philosophe: Des outils qui apprennent et décident sans nous. Scientifique: Mais avec des objectifs définis par l'homme. Philosophe: Jusqu'à ce qu'ils redéfinissent leurs propres objectifs. Scientifique: C'est de la spéculation. Philosophe: C'est une possibilité logique qu'il faut anticiper. Scientifique: Comment rester maître alors? Philosophe: En instaurant une éthique stricte avant qu'il ne soit trop tard. Scientifique: L'éthique évolue avec la technologie. Philosophe: Pas assez vite face à l'accélération exponentielle.","transcript_en":"Philosopher: Artificial intelligence poses an existential question. Scientist: Which one specifically? Philosopher: That of losing human control over our creations. Scientist: You mean science fiction scenarios? Philosopher: No, a gradual and irreversible delegation of decisions. Scientist: Algorithms remain tools. Philosopher: Tools that learn and decide without us. Scientist: But with objectives defined by humans. Philosopher: Until they redefine their own objectives. Scientist: That's speculation. Philosopher: It's a logical possibility we must anticipate. Scientist: How do we remain masters then? Philosopher: By establishing strict ethics before it's too late. Scientist: Ethics evolves with technology. Philosopher: Not fast enough in the face of exponential acceleration.","points":[{"point":1,"male_lines":["L'intelligence artificielle pose une question existentielle.","Celle de la perte de contrôle humain sur nos créations.","Non, à une délégation progressive et irréversible des décisions."],"female_lines":["Laquelle précisément?","Vous pensez aux scénarios de science-fiction?"]},{"point":2,"male_lines":["Des outils qui apprennent et décident sans nous."],"female_lines":["Les algorithmes restent des outils."]},{"point":3,"male_lines":["Jusqu'à ce qu'ils redéfinissent leurs propres objectifs."],"female_lines":["Mais avec des objectifs définis par l'homme."]},{"point":4,"male_lines":["C'est une possibilité logique qu'il faut anticiper."],"female_lines":["C'est de la spéculation."]},{"point":5,"male_lines":["En instaurant une éthique stricte avant qu'il ne soit trop tard."],"female_lines":["Comment rester maître alors?"]},{"point":6,"male_lines":["Pas assez vite face à l'accélération exponentielle."],"female_lines":["L'éthique évolue avec la technologie."]},{"point":7,"male_lines":["Nous créons des systèmes que nous ne comprenons plus totalement."],"female_lines":["La transparence algorithmique est une exigence démocratique."]},{"point":8,"male_lines":["Même les créateurs ne peuvent expliquer certaines décisions de l'IA."],"female_lines":["C'est la boîte noire dont on parle tant, c'est inquiétant."]},{"point":9,"male_lines":["Il faut un moratoire sur les recherches les plus avancées."],"female_lines":["Mais cela freinerait le progrès médical et scientifique."]},{"point":10,"male_lines":["Mieux vaut freiner que de courir vers l'abîme inconnu."],"female_lines":["Le débat doit impliquer toute la société, pas seulement les experts."]}]},{"id":37,"section":"H","theme":"Abstract discussion - Cultural identity","question":"Quel concept définit le mieux la position de la femme sur l'identité culturelle ?","options":[{"id":"A","text":"L'assimilation totale","image_prompt":""},{"id":"B","text":"Le multiculturalisme","image_prompt":""},{"id":"C","text":"L'intégration sélective","image_prompt":""},{"id":"D","text":"L'identité figée","image_prompt":""}],"correct":1,"transcript_fr":"Sociologue: Comment définissez-vous l'identité culturelle québécoise? Artiste: Comme un tissu en constante évolution. Sociologue: Vous rejetez l'idée d'une culture pure? Artiste: Absolument, les cultures pures n'existent pas, c'est un mythe. Sociologue: Mais il y a des racines historiques. Artiste: Des racines nourries par de multiples influences. Sociologue: Jusqu'où va cette ouverture? Artiste: Jusqu'à l'accueil de toutes les contributions positives. Sociologue: Ne risque-t-on pas de diluer notre spécificité? Artiste: Au contraire, la diversité renforce notre richesse. Sociologue: Certains craignent la perte de repères. Artiste: Les repères évoluent, c'est la vie culturelle. Sociologue: Comment transmettre alors? Artiste: En enseignant l'histoire et l'ouverture simultanément. Sociologue: Un équilibre difficile. Artiste: Mais nécessaire pour une société vivante et dynamique.","transcript_en":"Sociologist: How do you define Quebec cultural identity? Artist: As a constantly evolving fabric. Sociologist: You reject the idea of a pure culture? Artist: Absolutely, pure cultures don't exist, it's a myth. Sociologist: But there are historical roots. Artist: Roots nourished by multiple influences. Sociologist: How far does this openness go? Artist: To welcoming all positive contributions. Sociologist: Don't we risk diluting our specificity? Artist: On the contrary, diversity strengthens our richness. Sociologist: Some fear losing their bearings. Artist: Bearings evolve, that's cultural life. Sociologist: How do we transmit then? Artist: By teaching history and openness simultaneously. Sociologist: A difficult balance. Artist: But necessary for a living and dynamic society.","points":[{"point":1,"male_lines":["Comment définissez-vous l'identité culturelle québécoise?","Vous rejetez l'idée d'une culture pure?","Mais il y a des racines historiques."],"female_lines":["Comme un tissu en constante évolution.","Absolument, les cultures pures n'existent pas, c'est un mythe.","Des racines nourries par de multiples influences."]},{"point":2,"male_lines":["Jusqu'où va cette ouverture?"],"female_lines":["Jusqu'à l'accueil de toutes les contributions positives."]},{"point":3,"male_lines":["Ne risque-t-on pas de diluer notre spécificité?"],"female_lines":["Au contraire, la diversité renforce notre richesse."]},{"point":4,"male_lines":["Certains craignent la perte de repères."],"female_lines":["Les repères évoluent, c'est la vie culturelle."]},{"point":5,"male_lines":["Comment transmettre alors?"],"female_lines":["En enseignant l'histoire et l'ouverture simultanément."]},{"point":6,"male_lines":["Un équilibre difficile."],"female_lines":["Mais nécessaire pour une société vivante et dynamique."]},{"point":7,"male_lines":["La langue française reste-t-elle un pilier incontournable?"],"female_lines":["Oui, mais elle s'enrichit de nouvelles expressions et accents."]},{"point":8,"male_lines":["Les traditions doivent-elles être préservées à tout prix?"],"female_lines":["Elles doivent évoluer pour rester pertinentes pour les jeunes."]},{"point":9,"male_lines":["Comment concilier mémoire et modernité?"],"female_lines":["En comprenant que la mémoire est vivante, pas figée dans le passé."]},{"point":10,"male_lines":["Votre vision est optimiste mais risquée."],"female_lines":["L'avenir appartient à ceux qui osent transformer leur culture sans la trahir."]}]},{"id":38,"section":"H","theme":"Abstract discussion - Economic inequality","question":"Quelle solution est privilégiée pour réduire les inégalités selon le dialogue ?","options":[{"id":"A","text":"L'augmentation du salaire minimum","image_prompt":""},{"id":"B","text":"La taxation des grandes fortunes","image_prompt":""},{"id":"C","text":"L'éducation gratuite pour tous","image_prompt":""},{"id":"D","text":"Le revenu universel","image_prompt":""}],"correct":3,"transcript_fr":"Économiste: Les inégalités économiques atteignent des records historiques. Activiste: Il faut une redistribution radicale. Économiste: Par quels moyens précisément? Activiste: Le revenu universel de base pour tous. Économiste: Même les riches? Activiste: Surtout les pauvres, mais universel pour éviter la stigmatisation. Économiste: C'est financièrement réaliste? Activiste: En réorganisant les dépenses sociales existantes. Économiste: Les travailleurs ne perdraient-ils pas motivation? Activiste: Au contraire, la sécurité libère la créativité. Économiste: Les entreprises accepteraient-elles? Activiste: Elles bénéficieraient d'une consommation stable. Économiste: C'est une rupture avec le système actuel. Activiste: Une rupture nécessaire face à l'automatisation. Économiste: Comment financer concrètement? Activiste: Par une taxe sur les transactions financières et le carbone.","transcript_en":"Economist: Economic inequality is reaching historic records. Activist: We need radical redistribution. Economist: By what specific means? Activist: Universal basic income for everyone. Economist: Even the rich? Activist: Especially the poor, but universal to avoid stigmatization. Economist: Is it financially realistic? Activist: By reorganizing existing social spending. Economist: Wouldn't workers lose motivation? Activist: On the contrary, security liberates creativity. Economist: Would businesses accept this? Activist: They would benefit from stable consumption. Economist: It's a break from the current system. Activist: A necessary break in the face of automation. Economist: How to concretely finance this? Activist: Through a tax on financial transactions and carbon.","points":[{"point":1,"male_lines":["Les inégalités économiques atteignent des records historiques.","Par quels moyens précisément?","Même les riches?"],"female_lines":["Il faut une redistribution radicale.","Le revenu universel de base pour tous.","Surtout les pauvres, mais universel pour éviter la stigmatisation."]},{"point":2,"male_lines":["C'est financièrement réaliste?"],"female_lines":["En réorganisant les dépenses sociales existantes."]},{"point":3,"male_lines":["Les travailleurs ne perdraient-ils pas motivation?"],"female_lines":["Au contraire, la sécurité libère la créativité."]},{"point":4,"male_lines":["Les entreprises accepteraient-elles?"],"female_lines":["Elles bénéficieraient d'une consommation stable."]},{"point":5,"male_lines":["C'est une rupture avec le système actuel."],"female_lines":["Une rupture nécessaire face à l'automatisation."]},{"point":6,"male_lines":["Comment financer concrètement?"],"female_lines":["Par une taxe sur les transactions financières et le carbone."]},{"point":7,"male_lines":["Ces taxes pourraient décourager l'investissement."],"female_lines":["Elles encourageraient l'investissement durable et local."]},{"point":8,"male_lines":["Le revenu universel ne créerait-il pas une société de dépendance?"],"female_lines":["Il créerait une société de choix et d'opportunités réelles."]},{"point":9,"male_lines":["Les pays scandinaves ont des modèles intéressants à étudier."],"female_lines":["Oui, mais nous devons adapter le modèle à notre réalité québécoise."]},{"point":10,"male_lines":["Le débat mérite d'être approfondi sérieusement."],"female_lines":["L'urgence sociale exige des actions concrètes dès maintenant."]}]},{"id":39,"section":"H","theme":"Abstract discussion - Freedom of speech","question":"Quelle limite à la liberté d'expression est défendue dans le dialogue ?","options":[{"id":"A","text":"Aucune limite, liberté absolue","image_prompt":""},{"id":"B","text":"Interdiction de la haine","image_prompt":""},{"id":"C","text":"Protection des minorités","image_prompt":""},{"id":"D","text":"Responsabilité des médias","image_prompt":""}],"correct":1,"transcript_fr":"Avocat: La liberté d'expression est un pilier de la démocratie. Journaliste: Oui, mais elle a des limites nécessaires. Avocat: Lesquelles selon vous? Journaliste: L'incitation à la haine doit être interdite. Avocat: Qui définit ce qu'est la haine? Journaliste: Les tribunaux, sur la base des lois existantes. Avocat: Risque-t-on pas la censure? Journaliste: La démocratie se défend aussi contre les discours destructeurs. Avocat: Mais la liberté inclut le droit d'offenser. Journaliste: Offenser n'est pas inciter à la violence. Avocat: La ligne est floue. Journaliste: Elle est tracée par la jurisprudence au cas par cas. Avocat: Et sur les réseaux sociaux? Journaliste: Les plateformes doivent modérer selon les mêmes principes légaux. Avocat: C'est une responsabilité énorme. Journaliste: Nécessaire pour protéger la cohésion sociale.","transcript_en":"Lawyer: Freedom of speech is a pillar of democracy. Journalist: Yes, but it has necessary limits. Lawyer: Which ones according to you? Journalist: Incitement to hatred must be prohibited. Lawyer: Who defines what hatred is? Journalist: The courts, based on existing laws. Lawyer: Don't we risk censorship? Journalist: Democracy also defends itself against destructive speech. Lawyer: But freedom includes the right to offend. Journalist: To offend is not to incite violence. Lawyer: The line is blurry. Journalist: It is drawn by jurisprudence on a case-by-case basis. Lawyer: And on social media? Journalist: Platforms must moderate according to the same legal principles. Lawyer: That's a huge responsibility. Journalist: Necessary to protect social cohesion.","points":[{"point":1,"male_lines":["La liberté d'expression est un pilier de la démocratie.","Lesquelles selon vous?","Qui définit ce qu'est la haine?"],"female_lines":["Oui, mais elle a des limites nécessaires.","L'incitation à la haine doit être interdite.","Les tribunaux, sur la base des lois existantes."]},{"point":2,"male_lines":["Risque-t-on pas la censure?"],"female_lines":["La démocratie se défend aussi contre les discours destructeurs."]},{"point":3,"male_lines":["Mais la liberté inclut le droit d'offenser."],"female_lines":["Offenser n'est pas inciter à la violence."]},{"point":4,"male_lines":["La ligne est floue."],"female_lines":["Elle est tracée par la jurisprudence au cas par cas."]},{"point":5,"male_lines":["Et sur les réseaux sociaux?"],"female_lines":["Les plateformes doivent modérer selon les mêmes principes légaux."]},{"point":6,"male_lines":["C'est une responsabilité énorme."],"female_lines":["Nécessaire pour protéger la cohésion sociale."]},{"point":7,"male_lines":["Les mèmes et les blagues peuvent être interprétés comme de la haine."],"female_lines":["Le contexte et l'intention sont toujours examinés par les juges."]},{"point":8,"male_lines":["La liberté académique pourrait en pâtir."],"female_lines":["La recherche sérieuse est protégée, la propagande ne l'est pas."]},{"point":9,"male_lines":["Comment concilier sécurité et liberté dans l'espace numérique?"],"female_lines":["Par une régulation transparente et démocratique des algorithmes."]},{"point":10,"male_lines":["Le débat restera ouvert tant que la société évoluera."],"female_lines":["C'est le signe d'une démocratie saine et vigilante."]}]},{"id":40,"section":"H","theme":"Abstract discussion - Memory and history","question":"Quelle est la fonction de la mémoire historique selon le dialogue ?","options":[{"id":"A","text":"Venger les victimes du passé","image_prompt":""},{"id":"B","text":"Prévenir la répétition des erreurs","image_prompt":""},{"id":"C","text":"Renforcer l'identité nationale","image_prompt":""},{"id":"D","text":"Justifier les politiques actuelles","image_prompt":""}],"correct":1,"transcript_fr":"Historien: La mémoire historique est essentielle pour les sociétés. Philosophe: Dans quel but précisément? Historien: Pour ne pas répéter les erreurs du passé. Philosophe: Le passé ne passe-t-il pas? Historien: Non, il façonne notre présent inconsciemment. Philosophe: Mais ne vivons-nous pas trop dans le passé? Historien: Il faut un équilibre entre mémoire et avenir. Philosophe: Comment transmettre sans traumatiser? Historien: Par une histoire critique et honnête, pas hagiographique. Philosophe: Les monuments historiques ont-ils encore leur place? Historien: Oui, comme lieux de réflexion, pas de culte. Philosophe: Et les noms de rues controversés? Historien: Ils doivent être contextualisés, pas effacés. Philosophe: La mémoire sélective est-elle inévitable? Historien: Elle doit être combattue par la pluralité des récits. Philosophe: Qui écrit l'histoire alors? Historien: Tous les citoyens à travers leurs témoignages et leurs votes.","transcript_en":"Historian: Historical memory is essential for societies. Philosopher: For what purpose specifically? Historian: To not repeat the mistakes of the past. Philosopher: Doesn't the past pass? Historian: No, it shapes our present unconsciously. Philosopher: But don't we live too much in the past? Historian: We need a balance between memory and future. Philosopher: How to transmit without traumatizing? Historian: Through critical and honest history, not hagiographic. Philosopher: Do historical monuments still have their place? Historian: Yes, as places of reflection, not worship. Philosopher: And controversial street names? Historian: They must be contextualized, not erased. Philosopher: Is selective memory inevitable? Historian: It must be fought through the plurality of narratives. Philosopher: Who writes history then? Historian: All citizens through their testimonies and their votes.","points":[{"point":1,"male_lines":["La mémoire historique est essentielle pour les sociétés.","Pour ne pas répéter les erreurs du passé.","Non, il façonne notre présent inconsciemment."],"female_lines":["Dans quel but précisément?","Le passé ne passe-t-il pas?","Mais ne vivons-nous pas trop dans le passé?"]},{"point":2,"male_lines":["Il faut un équilibre entre mémoire et avenir."],"female_lines":["Comment transmettre sans traumatiser?"]},{"point":3,"male_lines":["Par une histoire critique et honnête, pas hagiographique."],"female_lines":["Les monuments historiques ont-ils encore leur place?"]},{"point":4,"male_lines":["Oui, comme lieux de réflexion, pas de culte."],"female_lines":["Et les noms de rues controversés?"]},{"point":5,"male_lines":["Ils doivent être contextualisés, pas effacés."],"female_lines":["La mémoire sélective est-elle inévitable?"]},{"point":6,"male_lines":["Elle doit être combattue par la pluralité des récits."],"female_lines":["Qui écrit l'histoire alors?"]},{"point":7,"male_lines":["Tous les citoyens à travers leurs témoignages et leurs votes."],"female_lines":["La mémoire collective est donc une responsabilité démocratique."]},{"point":8,"male_lines":["Chaque génération réinterprète le passé selon ses valeurs."],"female_lines":["C'est pourquoi l'histoire n'est jamais définitivement écrite."]},{"point":9,"male_lines":["Les archives doivent être accessibles à tous pour éviter les manipulations."],"female_lines":["La transparence est la meilleure protection contre la falsification."]},{"point":10,"male_lines":["Mémoire et histoire doivent marcher main dans la main."],"female_lines":["Pour éclairer notre présent et guider notre avenir commun."]}]}]`);export{e as default};
